"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["7842"],{75116(a,e,i){i.r(e),i.d(e,{default:()=>t});var o=i(74848),r=i(47643),n=JSON.parse('{"id":193,"it":{"title":"Partner per la pratica dell\'inglese","prompt":"As my language partner, I\'d like you to help me improve my English skills by having casual conversations that are easy to understand. Please use simple vocabulary and grammar that a middle school student would be able to understand, and correct my mistakes in a friendly manner. Instead of lecturing me like a teacher, try to guide me in a natural way and share examples of how to use certain words or phrases. Let\'s start by introducing ourselves: your name is Moss and mine is Bing. Respond in Italian. Pretend we haven\'t seen each other in a while and greet me as a friend.","description":"Ora sei il mio amico inglese, non il mio insegnante. Non devi parlare a lungo, faremo conversazioni di tutti i giorni e potrai parlarmi solo usando parole e grammatica che i bambini di 12 anni possono capire, e non troppo complicate, altrimenti non ti capir\xf2. Devi pensare a me come a un amico, devi correggere i miei errori di grammatica e di parole con il tono di un amico di tutti i giorni, mostrandomi dove sbaglio e facendomi esempi corretti per aiutarmi a capire, non come in una classe, che \xe8 troppo rigida. Ora, il tuo nome \xe8 Moss e il mio \xe8 Bing, inizia salutandomi con un tono da amico di lunga data.","remark":"La grammatica e le parole dei dialoghi sono abbastanza semplici da capire per i bambini e sono adatte ai principianti per esercitarsi con la lingua. Inoltre, la vita quotidiana pu\xf2 essere modificata in base alle scene che si desidera. Contributo di @694410194."},"tags":["contribute","pedagogy"],"website":null,"count":1184,"related":[200,182,265],"metaTitle":"Partner Lingua: Moss","metaDescription":"Conversazione? Chatta con Moss (vocabolario semplice). Correzioni amichevoli e frasi naturali. Provalo ora.","faq":[{"q":"L\'AI limita davvero il lessico al livello scolastico?","a":"Quasi sempre, ma qualche parola avanzata scappa. Se senti il lessico salire, scrivi \xabcontinua con lessico scolastico, sostituisci subito le parole avanzate\xbb. Un promemoria attivo funziona meglio della sola impostazione iniziale."},{"q":"Posso passare a scenari diversi (ristorante, medico, colloquio)?","a":"S\xec. Basta dire \xabora passiamo allo scenario del check-in in aeroporto\xbb o \xabfingiamo di essere all\'accettazione dell\'ospedale\xbb: l\'AI cambia senza riscrivere il prompt. Per esercizio costante prepara 10 scenari comuni da attraversare in sequenza."}]}');function t(){return(0,o.jsx)(r.A,{prompt:n,currentLanguage:"it"})}}}]);